// Mapeia o JSON do ERP para o contrato do Radar.
// Ajuste os caminhos conforme o ERP (ver n8n-erp.md).
const rows = [];
for (const item of $input.all()) {
  const v = item.json;
  // EXEMPLO genérico — troque pelos campos reais do seu ERP:
  rows.push({
    data: v.data || v.emission || v.dataEmissao,
    cliente: v.cliente || v.customer?.name || v.contato?.nome,
    produto: v.produto || v.item?.descricao || v.description,
    quantidade: Number(v.quantidade || v.quantity || 1),
    valor: Number(v.valor || v.value || v.valor_total || 0),
    telefone: v.telefone || v.contato?.telefone || undefined,
    email: v.email || v.contato?.email || undefined,
  });
}
return [{ json: { rows } }];
